import{_ as e,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"FAQ: トラブルシューティング | opencode-md-table-formatter","description":"opencode-md-table-formatter プラグインのよくある質問とトラブルシューティング方法を学びます。テーブルフォーマットの問題を素早く特定し、設定、構造、配置などの複雑な問題を解決します。","frontmatter":{"title":"FAQ: トラブルシューティング | opencode-md-table-formatter","sidebarTitle":"問題が発生した場合","subtitle":"FAQ: トラブルシューティング | opencode-md-table-formatter","description":"opencode-md-table-formatter プラグインのよくある質問とトラブルシューティング方法を学びます。テーブルフォーマットの問題を素早く特定し、設定、構造、配置などの複雑な問題を解決します。","order":3},"headers":[],"relativePath":"ja/franlol/opencode-md-table-formatter/faq/index.md","filePath":"ja/franlol/opencode-md-table-formatter/faq/index.md"}'),l={name:"ja/franlol/opencode-md-table-formatter/faq/index.md"};function i(n,a,d,s,h,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h1><h2 id="章の概要" tabindex="-1">章の概要 <a class="header-anchor" href="#章の概要" aria-label="Permalink to &quot;章の概要&quot;">​</a></h2><p>この章では、opencode-md-table-formatter プラグインのよくある質問とトラブルシューティング方法について説明し、テーブルのフォーマット中に遭遇する様々な問題を素早く特定して解決するのに役立ちます。</p><hr><h2 id="サブページナビゲーション" tabindex="-1">サブページナビゲーション <a class="header-anchor" href="#サブページナビゲーション" aria-label="Permalink to &quot;サブページナビゲーション&quot;">​</a></h2><h3 id="よくある質問-テーブルがフォーマットされない場合" tabindex="-1"><a href="./troubleshooting/">よくある質問：テーブルがフォーマットされない場合</a> <a class="header-anchor" href="#よくある質問-テーブルがフォーマットされない場合" aria-label="Permalink to &quot;[よくある質問：テーブルがフォーマットされない場合](troubleshooting/)&quot;">​</a></h3><p>プラグイン使用時のよくある質問と解決策を包括的に紹介します：</p><ul><li><strong>テーブルがフォーマットされない</strong>：設定、バージョン要件、OpenCode の再起動を確認</li><li><strong>無効なテーブル構造</strong>：&quot;invalid structure&quot; エラーの意味を理解し、正しいテーブル構文を学習</li><li><strong>フォーマット失敗</strong>：&quot;table formatting failed&quot; エラーと例外状況を処理</li><li><strong>サポートされていないテーブルタイプ</strong>：HTML テーブル、複数行セルなどの制限されたシナリオを理解</li><li><strong>フォーマット後に整列しない</strong>：非表示モード、セルの超過長、インラインコードなどの問題を調査</li></ul><hr><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><p><a href="./../start/features/">機能概要</a> を完了した後、実際の問題が発生したときにこの章を参照するか、問題解決のリファレンスマニュアルとして使用することをお勧めします。</p><p>以下の順序で学習できます：</p><ol><li><strong>問題が発生したとき</strong>：症状に基づいて問題のタイプを特定します（テーブルがフォーマットされない、エラーメッセージなど）</li><li><strong>段階的なトラブルシューティング</strong>：トラブルシューティングガイドのチェックリストに従って一つずつ検証</li><li><strong>深い理解</strong>：<a href="./../advanced/table-spec/">テーブル仕様</a>と<a href="./../advanced/concealment-mode/">非表示モードの原理</a>を読んで技術的な詳細を理解</li><li><strong>既知の制限</strong>：<a href="./../appendix/limitations/">既知の制限</a>を確認してプラグインの境界を理解</li></ol><hr><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>この章を学習する前に、以下を完了することをお勧めします：</p><ul><li>✅ <a href="./../start/getting-started/">1分で始める：インストールと設定</a> - プラグインのインストールと設定方法を理解</li><li>✅ <a href="./../start/features/">機能概要：自動フォーマットの魔法</a> - プラグインのコア機能と動作原理を理解</li></ul><p>また、以下の知識が必要です：</p><ul><li>Markdown テーブルの基本構文に慣れていること</li><li>OpenCode のプラグイン設定方法（<code>opencode.jsonc</code>）を理解していること</li></ul><hr><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を完了した後、以下のトピックを学習できます：</p><ul><li><p><strong>高度な知識</strong>：</p><ul><li><a href="./../advanced/table-spec/">テーブル仕様：どのようなテーブルがフォーマット可能か</a> - 有効なテーブルの構造要件を習得</li><li><a href="./../advanced/concealment-mode/">非表示モードの原理：なぜ幅の計算が重要なのか</a> - OpenCode の非表示モードの動作原理を理解</li><li><a href="./../advanced/alignment/">配置方法の詳細：左揃え、中央揃え、右揃え</a> - 3種類の配置方法の構文と効果を習得</li></ul></li><li><p><strong>技術的な詳細</strong>：</p><ul><li><a href="./../appendix/limitations/">既知の制限：プラグインの境界はどこにあるか</a> - プラグインの既知の制限と適用されないシナリオを理解</li><li><a href="./../appendix/tech-details/">技術詳細：キャッシュメカニズムとパフォーマンス最適化</a> - プラグインの内部キャッシュメカニズムとパフォーマンス最適化戦略を理解</li></ul></li></ul><hr>',24)])])}const m=e(l,[["render",i]]);export{f as __pageData,m as default};
